// orders.proto
syntax = "proto3";
service OrderService {
    rpc GetOrder (GetOrderRequest) returns (OrderResponse);
    rpc ListOrders (ListOrdersRequest) returns (stream OrderResponse); // server streaming
    rpc CreateOrder (stream CreateOrderRequest) returns (CreateOrderResponse); // client streaming
}
message GetOrderRequest { int32 id = 1; }
message OrderResponse {
    int32 id = 1; string status = 2; double total = 3;
    google.protobuf.Timestamp created_at = 4;
}

// Server implementation
public class OrderGrpcService(IOrderRepository repo) : OrderService.OrderServiceBase
{
    public override async Task<OrderResponse> GetOrder(
        GetOrderRequest req, ServerCallContext ctx)
    {
        var order = await repo.GetAsync(req.Id, ctx.CancellationToken)
            ?? throw new RpcException(new Status(StatusCode.NotFound, $"Order {req.Id} not found"));
        return new OrderResponse { Id = order.Id, Status = order.Status, Total = order.Total };
    }

    public override async Task ListOrders(
        ListOrdersRequest req, IServerStreamWriter<OrderResponse> stream, ServerCallContext ctx)
    {
        await foreach (var order in repo.GetStreamAsync(ctx.CancellationToken))
            await stream.WriteAsync(new OrderResponse { Id = order.Id });
    }
}

// Registration
builder.Services.AddGrpc(opt => { opt.EnableDetailedErrors = builder.Environment.IsDevelopment(); });
app.MapGrpcService<OrderGrpcService>();
